 while(1) {
 // P10.2 ŪēÄžĚĄ ŪÜ†ÍłÄ.
 IfxPort_setPinState(&MODULE_P10, 2, IfxPort_State_toggled);

 // Hard loop delay.
 for(int i = 0; i < 50000000; i++) {}
 }

 return 1;
}
