 .def("baudrate", &lot::Uart::baudrate)
 .def("mode", &lot::Uart::mode)
 .def("available", &lot::Uart::available)
 .def("transmit",
 [](lot::Uart &self, py::bytes data) {
 std::string str = data;
 if(str.size() > 0) {
 self.transmit(reinterpret_cast(
 const_cast(str.c_str())),
 str.size());
